 32: export function syncRangeEmbedWrapperPadding(embedEl: HTMLElement, wrapper: HTMLElement): void {
 33: 	// Reading-range wrappers are created outside `.markdown-embed-content`, so they don't naturally
 34: 	// pick up Obsidian's embed preview padding rule.
 35: 	//
 36: 	// Prefer the same token Obsidian uses so theme/layout changes propagate. In some test/DOM
 37: 	// environments (notably JSDOM), `var(...)` may be rejected as an invalid inline style value;
 38: 	// fall back to copying computed padding from the native embed preview.
 39: 	try {
 40: 		wrapper.style.padding = "var(--embed-padding, 0px)";
 41: 		if (wrapper.style.padding) return;
 42: 	} catch {
 43: 		// ignore
 44: 	}
 45: 
 46: 	try {
 47: 		const nativePreview = embedEl.querySelector<HTMLElement>(".markdown-embed-content .markdown-preview-view");
 48: 		if (!nativePreview) return;
 49: 		const cs = getComputedStyle(nativePreview);
 50: 		wrapper.style.paddingLeft = cs.paddingLeft;
 51: 		wrapper.style.paddingRight = cs.paddingRight;
 52: 	} catch {
 53: 		// ignore
 54: 	}
 55: }
